<?php
 namespace WPAICG\Vector\ManagerMethods; use WP_Error; if (!defined('ABSPATH')) { exit; } function list_files_in_store_logic(string $provider, string $vector_store_id, array $provider_config, array $query_params = []): array|WP_Error { $strategy = get_connected_strategy_logic($provider, $provider_config); if (is_wp_error($strategy)) { return $strategy; } if (method_exists($strategy, 'list_vector_store_files')) { return $strategy->list_vector_store_files($vector_store_id, $query_params); } return new WP_Error('method_not_supported', __('Listing files is not supported by this provider strategy.', 'gpt3-ai-content-generator')); }